sed -i '/^// CompletionOptions is a set of options to control the handling of shell completion/a\t// defaultFlagCompletionFunc is the default completion function for all flags of this command. If a flag
	// has its own specific completion function registered via RegisterFlagCompletionFunc, that function will be used.
	// Otherwise, this default function is used as a fallback.
	defaultFlagCompletionFunc func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective)' /workspace/repo/command.go

cat <<'EOF' > /workspace/repo/completions_new.go.patch
--- a/completions.go
+++ b/completions.go
@@ -79,6 +79,12 @@ const (
 	// ShellCompDirectiveKeepOrder indicates that the shell should preserve the order
 	// in which the completions are provided
 	ShellCompDirectiveKeepOrder

+	// ShellCompDirectiveNoDescription indicates that descriptions should not be
+	// displayed in the completion results
+	ShellCompDirectiveNoDescription
+
 	// ===========================================================================

 	// All directives using iota should be above this one.
@@ -178,6 +184,10 @@ func (d ShellCompDirective) string() string {
 	if d&ShellCompDirectiveKeepOrder != 0 {
 		directives = append(directives, "ShellCompDirectiveKeepOrder")
 	}
+	if d&ShellCompDirectiveNoDescription != 0 {
+		directives = append(directives, "ShellCompDirectiveNoDescription")
+	}
+
 	if len(directives) == 0 {
 		directives = append(directives, "ShellCompDirectiveDefault")
 	}
@@ -155,12 +165,17 @@ func GetFlagCompletion(flag *pflag.Flag) (func(cmd *Command, args []string, toCo
 }

 // GetFlagCompletionByName returns the completion function for the given flag in the command by name, if available.
-func (c *Command) GetFlagCompletionByName(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
-	flag := c.Flags().Lookup(flagName)
+func (c *Command) GetFlagCompletionByName(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
+	flag := c.Flag(flagName)
 	if flag == nil {
 		return nil, false
 	}

 	return GetFlagCompletion(flag)
 }

+// GetFlagCompletion returns the completion function for the given flag, if available.
+// Deprecated: Use Command.GetFlagCompletionByName instead.
+func GetFlagCompletion(flag *pflag.Flag) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
+	flagCompletionMutex.RLock()
+	defer flagCompletionMutex.RUnlock()

 	completionFunc, exists := flagCompletionFunctions[flag]
 	return completionFunc, exists
