EOF

sed -i '203 a\n	// defaultFlagCompletionFunc is the default completion function for all flags of this command. If a flag
	// has its own specific completion function registered via RegisterFlagCompletionFunc, that function will be used.
	// Otherwise, this default function is used as a fallback.
	defaultFlagCompletionFunc func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective)' /workspace/repo/command.go

# Step 3: Add deprecation comment for GetFlagCompletion
sed -i '/^\/\/ GetFlagCompletion returns the completion function/,/^func GetFlagCompletion/ {
    /^\/\/ GetFlagCompletion returns the completion function$/a\
// Deprecated: Use Command.GetFlagCompletionByName instead.
}' /workspace/repo/completions.go

sed -i '165 a\n// RegisterDefaultFlagCompletionFunc should be called to register a default completion function for all flags of this command.
// This function acts as a fallback when no specific completion logic has been defined for a particular flag.
func (c *Command) RegisterDefaultFlagCompletionFunc(f func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective)) {
	c.defaultFlagCompletionFunc = f
}

// GetFlagCompletionFunc returns the completion function for the given flag in the command, if available.
// It first checks for a flag-specific completion function registered via RegisterFlagCompletionFunc.
// If no specific function is found, it falls back to the default completion function registered via RegisterDefaultFlagCompletionFunc.
// Returns the completion function and a boolean indicating whether a function was found.
func (c *Command) GetFlagCompletionFunc(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
	flag := c.Flags().Lookup(flagName)
	if flag == nil {
		return nil, false
	}

	// First check for a flag-specific completion function
	flagCompletionMutex.RLock()
	completionFunc, exists := flagCompletionFunctions[flag]
	flagCompletionMutex.RUnlock()

	if exists {
		return completionFunc, true
	}

	// If no specific function, check for a default completion function
	if c.defaultFlagCompletionFunc != nil {
		return c.defaultFlagCompletionFunc, true
	}

	return nil, false
}' /workspace/repo/completions.go

sed -i '156 a\n// GetFlagCompletionByName returns the completion function for the given flag in the command by name, if available.
// It first checks for a flag-specific completion function registered via RegisterFlagCompletionFunc.
// If no specific function is found, it falls back to the default completion function registered via RegisterDefaultFlagCompletionFunc.
// Returns the completion function and a boolean indicating whether a function was found.
func (c *Command) GetFlagCompletionByName(flagName string) (func(cmd *Command, args []string, toComplete string) ([]string, ShellCompDirective), bool) {
	flag := c.Flags().Lookup(flagName)
	if flag == nil {
		return nil, false
	}

	// First check for a flag-specific completion function
	flagCompletionMutex.RLock()
	completionFunc, exists := flagCompletionFunctions[flag]
	flagCompletionMutex.RUnlock()

	if exists {
		return completionFunc, true
	}

	// If no specific function, check for a default completion function
	if c.defaultFlagCompletionFunc != nil {
		return c.defaultFlagCompletionFunc, true
