	return nil, false
}' /workspace/repo/completions.go

python3 << 'EOF'
# Read the file
with open('/workspace/repo/completions.go', 'r') as f:
    content = f.read()

# Find the initCompleteCmd function and update the description stripping logic
# The current logic checks `noDescriptions` based on cmd.CalledAs() == ShellCompNoDescRequestCmd
# We need to also check if the directive contains ShellCompDirectiveNoDescription

old_code = '''\t\t\tnoDescriptions := (cmd.CalledAs() == ShellCompNoDescRequestCmd)
\t\t\tfor _, comp := range completions {
\t\t\t\tif GetActiveHelpConfig(finalCmd) == activeHelpGlobalDisable {
\t\t\t\t\t// Remove all activeHelp entries in this case
\t\t\t\t\tif strings.HasPrefix(comp, activeHelpMarker) {
\t\t\t\t\t\tcontinue
\t\t\t\t\t}
\t\t\t\t}
\t\t\t\tif noDescriptions {
\t\t\t\t\t// Remove any description that may be included following a tab character.
\t\t\t\t\tcomp = strings.Split(comp, "\\t")[0]
\t\t\t\t}'''

new_code = '''\t\t\tnoDescriptions := (cmd.CalledAs() == ShellCompNoDescRequestCmd) || (directive&ShellCompDirectiveNoDescription != 0)
\t\t\tfor _, comp := range completions {
\t\t\t\tif GetActiveHelpConfig(finalCmd) == activeHelpGlobalDisable {
\t\t\t\t\t// Remove all activeHelp entries in this case
\t\t\t\t\tif strings.HasPrefix(comp, activeHelpMarker) {
\t\t\t\t\t\tcontinue
\t\t\t\t\t}
\t\t\t\t}
\t\t\t\tif noDescriptions {
\t\t\t\t\t// Remove any description that may be included following a tab character.
\t\t\t\t\tcomp = strings.Split(comp, "\\t")[0]
\t\t\t\t}'''

content = content.replace(old_code, new_code)

# Write the file
with open('/workspace/repo/completions.go', 'w') as f:
    f.write(content)

print("Updated initCompleteCmd successfully")
EOF

